   249→/// Unit Crate Collide Module
   250→/// 
   251→/// This module implements a crate that spawns a specified number of units
   252→/// of a specified type for the player who picks it up.
   253→pub struct UnitCrateCollide {
   254→    base: BaseCrateCollide,
   255→    module_data: UnitCrateCollideModuleData,
   256→    version: u32,
   257→}
   258→
   259→impl UnitCrateCollide {
   260→    /// Create a new UnitCrateCollide instance
   261→    /// 
   262→    /// # Arguments
   263→    /// * `object_id` - The ID of the object this module belongs to
   264→    /// * `module_data` - Configuration data for the unit crate collision behavior
   265→    pub fn new(object_id: ObjectID, module_data: UnitCrateCollideModuleData) -> Self {
   266→        Self {
   267→            base: BaseCrateCollide::new(object_id, module_data.base.clone()),
   268→            module_data,
   269→            version: 1,
   270→        }
   271→    }
   272→
   273→    /// Get the unit crate collision module data
   274→    pub fn get_unit_crate_collide_module_data(&self) -> &UnitCrateCollideModuleData {
   275→        &self.module_data
   276→    }
   277→
   278→    /// Get the current version of this module for serialization
   279→    pub fn get_version(&self) -> u32 {
   280→        self.version
   281→    }
   282→
   283→    /// Serialize this module's state
   284→    pub fn serialize<T: super::shroud_crate_collide::Serialize>(&self, xfer: &mut T) -> Result<(), CollisionError> {
   285→        xfer.write_version(self.version)
   286→            .map_err(|e| CollisionError::InvalidObject(format!("Serialization failed: {}", e)))?;
   287→        
   288→        // In a full implementation, would serialize the module data as well
   289→        
   290→        Ok(())
   291→    }
   292→
   293→    /// Deserialize this module's state
   294→    pub fn deserialize<T: super::shroud_crate_collide::Deserialize>(&mut self, xfer: &mut T) -> Result<(), CollisionError> {
   295→        let version = xfer.read_version()
   296→            .map_err(|e| CollisionError::InvalidObject(format!("Deserialization failed: {}", e)))?;
   297→        
   298→        if version != self.version {
   299→            return Err(CollisionError::InvalidObject(
   300→                format!("Version mismatch: expected {}, got {}", self.version, version)
   301→            ));
   302→        }
   303→        
   304→        Ok(())
   305→    }
   306→
   307→    /// Compute CRC for this module's state
   308→    pub fn compute_crc(&self) -> u32 {
   309→        let mut crc = 0u32;
   310→        crc ^= self.version;
   311→        crc ^= self.module_data.unit_count;
   312→        // Add unit type string hash
   313→        crc ^= self.module_data.unit_type.chars().fold(0u32, |acc, c| acc.wrapping_add(c as u32));
   314→        crc
   315→    }
   316→
   317→    /// Load post-processing after deserialization
   318→    pub fn load_post_process(&mut self) -> Result<(), CollisionError> {
   319→        // Perform any unit-specific post-processing here
   320→        Ok(())
   321→    }
   322→}
