   324→impl CollideModule for UnitCrateCollide {
   325→    fn on_collide(&mut self, other: Option<&dyn GameObject>, loc: &Coord3D, normal: &Coord3D) -> Result<(), CollisionError> {
   326→        if let Some(other_obj) = other {
   327→            if self.is_valid_to_execute(other_obj) {
   328→                // Execute the unit crate behavior
   329→                let success = self.execute_crate_behavior_internal(other_obj)?;
   330→                if !success {
   331→                    return Err(CollisionError::InvalidObject("Failed to execute unit crate behavior".to_string()));
   332→                }
   333→            }
   334→        }
   335→        
   336→        // Call base implementation for common collision handling
   337→        self.base.on_collide(other, loc, normal)
   338→    }
   339→
   340→    fn would_like_to_collide_with(&self, other: &dyn GameObject) -> bool {
   341→        self.is_valid_to_execute(other)
   342→    }
   343→}
   344→
   345→impl CrateCollide for UnitCrateCollide {
   346→    fn execute_crate_behavior(&mut self, other: &mut dyn GameObject) -> Result<bool, CollisionError> {
   347→        self.execute_crate_behavior_internal(other)
   348→    }
   349→
   350→    fn is_valid_to_execute(&self, other: &dyn GameObject) -> bool {
   351→        self.base.is_valid_to_execute(other)
   352→    }
   353→
   354→    fn get_crate_module_data(&self) -> &CrateCollideModuleData {
   355→        &self.module_data.base
   356→    }
   357→}
