   359→impl UnitCrateCollide {
   360→    /// Internal implementation of crate behavior execution
   361→    /// 
   362→    /// This method creates the specified number of units of the specified type
   363→    /// for the controlling player of the object that collided with this crate.
   364→    /// 
   365→    /// # Arguments
   366→    /// * `other` - The object that collided with this crate
   367→    /// 
   368→    /// # Returns
   369→    /// * `Ok(true)` if the crate behavior was successfully executed
   370→    /// * `Ok(false)` if the behavior could not be executed
   371→    /// * `Err(CollisionError)` if an error occurred during execution
   372→    fn execute_crate_behavior_internal(&self, other: &dyn GameObject) -> Result<bool, CollisionError> {
   373→        let unit_count = self.module_data.unit_count;
   374→        
   375→        // Find the unit template
   376→        let thing_factory = THING_FACTORY.lock().map_err(|e|
   377→            CollisionError::InvalidObject(format!("Failed to acquire thing factory lock: {}", e))
   378→        )?;
   379→        
   380→        let unit_template = match thing_factory.find_template(&self.module_data.unit_type) {
   381→            Some(template) => template,
   382→            None => {
   383→                return Err(CollisionError::InvalidObject(
   384→                    format!("Unit template '{}' not found", self.module_data.unit_type)
   385→                ));
   386→            }
   387→        };
   388→
   389→        // Get the player's default team (simplified - would need proper player lookup)
   390→        let creation_team = Team {
   391→            id: other.get_controlling_player() as u32,
   392→            player_id: other.get_controlling_player(),
   393→            name: format!("Team{}", other.get_controlling_player()),
   394→        };
   395→
   396→        let partition_manager = UNIT_PARTITION_MANAGER.lock().map_err(|e|
   397→            CollisionError::PartitionManagerError(format!("Failed to acquire partition manager lock: {}", e))
   398→        )?;
   399→
   400→        // Create the specified number of units
   401→        for _unit_index in 0..unit_count {
   402→            let mut new_obj = thing_factory.new_object(&unit_template, &creation_team)
   403→                .map_err(|e| CollisionError::InvalidObject(format!("Failed to create object: {}", e)))?;
   404→
   405→            // Set initial position and find a legal position around the crate
   406→            let mut creation_point = other.get_position();
   407→            let fp_options = FindPositionOptions::default();
   408→            
   409→            partition_manager.find_position_around(
   410→                &other.get_position(),
   411→                &fp_options,
   412→                &mut creation_point
   413→            )?;
   414→
   415→            // Set the object's position and orientation
   416→            new_obj.set_orientation(other.get_orientation());
   417→            new_obj.set_position(&creation_point);
   418→            
   419→            // In a real implementation, would add the object to the game world
   420→            println!("Created unit '{}' at {:?} for player {}", 
   421→                     unit_template.name, creation_point, other.get_controlling_player());
   422→        }
   423→
   424→        // Play a crate pickup sound
   425→        let audio_event = AudioEvent::new(other.get_id(), "crate_free_unit");
   426→        
   427→        let audio_system = AUDIO_SYSTEM.lock().map_err(|e|
   428→            CollisionError::AudioSystemError(format!("Failed to acquire audio system lock: {}", e))
   429→        )?;
   430→        
   431→        audio_system.play_crate_sound(&audio_event)?;
   432→
   433→        Ok(true)
   434→    }
   435→}
